class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

@final
class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle")
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

@final
class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    @override
    def area(self) -> float:
        # π * r², using 3.14159 as pi
        return 3.14159 * self.radius * self.radius

def print_shape_info(shape: Shape):
    print(f"{shape.name}: area = {shape.area()}")

def create_shape_collection() -> list[Shape]:
    shapes: list[Shape] = []
    shapes.append(Rectangle(4.0, 5.0))
    shapes.append(Circle(3.0))
    shapes.append(Rectangle(2.0, 2.0))
    return shapes
